1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = { type: string; cursed?: boolean; enchantment?: number };
12	type Step = { type: string; items: Item[] };
13	
14	const BLOCK_OF_3_PRICE = 60;
15	
16	const COMPONENT_TYPES = ["rune", "moonstone"];
17	
18	function countByType(items: Item[]): Record<string, number> {
19	  const counts: Record<string, number> = {};
20	  for (const item of items) {
21	    counts[item.type] = (counts[item.type] ?? 0) + 1;
22	  }
23	  return counts;
24	}
25	
26	function priceForType(type: string, count: number): number {
27	  if (COMPONENT_TYPES.includes(type) && count === 3) {
28	    return BLOCK_OF_3_PRICE;
29	  }
30	  return count * BASE_PREMIUM_BY_TYPE[type];
31	}
32	
33	function hasItemModifier(item: Item): boolean {
34	  return Boolean(item.cursed) || (item.enchantment ?? 0) >= 5;
35	}
36	
37	function itemPremium(item: Item): number {
38	  let premium = BASE_PREMIUM_BY_TYPE[item.type];
39	  if (item.cursed) {
40	    premium *= 1.5;
41	  }
42	  if ((item.enchantment ?? 0) >= 5) {
43	    premium *= 1.3;
44	  }
45	  return premium;
46	}
47	
48	function modifiedPremium(items: Item[]): number {
49	  return items
50	    .filter(hasItemModifier)
51	    .reduce((total, item) => total + itemPremium(item), 0);
52	}
53	
54	function plainPremium(items: Item[]): number {
55	  const counts = countByType(items.filter((item) => !hasItemModifier(item)));
56	  return Object.entries(counts).reduce(
57	    (total, [type, count]) => total + priceForType(type, count),
58	    0,
59	  );
60	}
61	
62	function basePremium(items: Item[]): number {
63	  return modifiedPremium(items) + plainPremium(items);
64	}
65	
66	export function runScenario(steps: Step[]): unknown[] {
67	  return steps.map((step) => ({
68	    premium: PROCESSING_FEE + basePremium(step.items),
69	  }));
70	}
